-- Create buyers table if not exists
CREATE TABLE IF NOT EXISTS buyers (
    id SERIAL PRIMARY KEY,
    legal_name VARCHAR(255) NOT NULL,
    trade_name VARCHAR(255),
    country VARCHAR(100) DEFAULT 'USA',
    state_region VARCHAR(100),
    city VARCHAR(100),
    address VARCHAR(255),
    zip_code VARCHAR(20),
    buyer_type VARCHAR(50),
    paca_license VARCHAR(20),
    product_specialties TEXT,
    annual_volume_usd BIGINT,
    credit_rating VARCHAR(10),
    payment_terms VARCHAR(20),
    status VARCHAR(20) DEFAULT 'ACTIVE',
    verification_status VARCHAR(20) DEFAULT 'PENDING',
    primary_contact VARCHAR(255),
    email VARCHAR(255),
    phone VARCHAR(50),
    created_at TIMESTAMP DEFAULT NOW(),
    updated_at TIMESTAMP DEFAULT NOW()
);

-- Create index on PACA license for fast lookups
CREATE INDEX IF NOT EXISTS idx_buyers_paca ON buyers(paca_license);
CREATE INDEX IF NOT EXISTS idx_buyers_state ON buyers(state_region);
CREATE INDEX IF NOT EXISTS idx_buyers_type ON buyers(buyer_type);

